def test_stop_windows_terminates_pidfile_process(
    monkeypatch: pytest.MonkeyPatch,
) -> None:
    monkeypatch.setattr("sys.platform", "win32")

    fake_proc = MagicMock()
    removed = []

    with (
        patch.object(pidfile, "read_pid", return_value=1234),
        patch.object(pidfile, "is_process_ours", return_value=True),
        patch.object(
            pidfile, "remove_pid", side_effect=lambda name: removed.append(name)
        ),
        patch("psutil.Process", return_value=fake_proc),
    ):
        supervisor.stop_service()

    fake_proc.terminate.assert_called_once()
    assert removed == [supervisor.SERVICE_PIDFILE_NAME]


