def test_restart_windows_terminates_then_launches(
    monkeypatch: pytest.MonkeyPatch, tmp_path: Path
) -> None:
    monkeypatch.setattr("sys.platform", "win32")
    monkeypatch.setattr(supervisor, "_TERMINATE_WAIT_SECONDS", 0.01)
    monkeypatch.setattr(supervisor.time, "sleep", lambda *_: None)
    monkeypatch.setattr(winutil, "pythonw_path", lambda: "C:\\fake\\pythonw.exe")
    supervisor.configure(config_path=tmp_path / "config.json")

    fake_proc = MagicMock()

    with (
        patch.object(pidfile, "read_pid", return_value=4321),
        patch.object(pidfile, "is_process_ours", return_value=True),
        patch.object(pidfile, "remove_pid"),
        patch("psutil.Process", return_value=fake_proc),
        patch("subprocess.Popen") as popen,
    ):
        supervisor.restart_service()

    fake_proc.terminate.assert_called_once()
    popen.assert_called_once()
    cmd = popen.call_args[0][0]
    assert cmd[0] == "C:\\fake\\pythonw.exe"
    assert cmd[1:4] == ["-m", "agentpulse", "--config"]
    assert cmd[4] == str(tmp_path / "config.json")


